import sys

def hex_to_bytes(hex_str):
    return bytes.fromhex(hex_str.replace(" ", "").replace("\n", ""))

def test_parse(data):
    idx = 0
    def read_byte(): nonlocal idx; v = data[idx]; idx += 1; return v
    def read_ushort(): nonlocal idx; v = int.from_bytes(data[idx:idx+2], "little"); idx += 2; return v
    def read_uint(): nonlocal idx; v = int.from_bytes(data[idx:idx+4], "little"); idx += 4; return v
    def read_ulong(): nonlocal idx; v = int.from_bytes(data[idx:idx+8], "little"); idx += 8; return v
    
    ticket = read_uint()
    refObjID = read_uint()
    scale = read_byte()
    curLevel = read_byte()
    maxLevel = read_byte()
    exp = read_ulong()
    spOffset = read_uint()
    gold = read_ulong()
    sp = read_uint()
    statPoint = read_ushort()
    zerkLevel = read_byte()
    gatheredExp = read_uint()
    hp = read_uint()
    mp = read_uint()
    autoInvestStat = read_byte()
    dailyPK = read_byte()
    totalPK = read_ushort()
    pkPenaltyPoint = read_uint()
    zerkLevel2 = read_byte()
    freePvP = read_byte()

    print(f"RefObjID: {refObjID}, Lvl: {curLevel}, MaxLvl: {maxLevel}, Exp: {exp}")
    print(f"HP: {hp}, MP: {mp}, Gold: {gold}")
    
    # Inventory
    invSize = read_byte()
    invCount = read_byte()
    print(f"InvSize: {invSize}, InvCount: {invCount}")
    
    for i in range(invCount):
        slot = read_byte()
        rentType = read_uint()
        if rentType != 0:
            read_ushort() # rent time
        
        itemID = read_uint()
        print(f"Slot: {slot}, Rent: {rentType}, ItemID: {itemID}")
        # Need to know ItemID type (equip/consumable) to know length...
        
    print(f"Parsed up to {idx} / {len(data)}")

